sysauto_script.script:
getNewAPIToken();

function getNewAPIToken() {
	var tanUtil = new x_taniu_tan_core.TaniumIntegrationCore();
	if (tanUtil.updateAPIToken()) {
		gs.debug(
			'Success setting new Tanium API token with Scheduled Script Execution at ' +
			'sysauto_script.do?sys_id=30706e092f40f8101ba85d492799b639'
		);
		return true;
	} else {
		gs.error('Failed to set new Tanium API token with Scheduled Script Execution at ' +
			'sysauto_script.do?sys_id=30706e092f40f8101ba85d492799b639'
		);
		return false;
	}
}
